# post.ex
defmodule MyApp.Blog.Post do
  @derive {Phoenix.Param, key: :id}
  schema "posts" do
    field :title, :string
    field :content, :text
  end

  def changeset(post_or_changeset, attrs) do
    post_or_changeset
    |> Ecto.Changeset.cast(attrs, [:title, :content])
    |> Ecto.Changeset.validate_required([:title, :content])
  end
end

# post_controller.ex
defmodule MyApp.BlogWeb.PostController do
  use MyApp.Web, :controller

  def show(conn, %{"id" => id}) do
    post = Repo.get!(Post, id)
    render conn, "show.html", post: post
  end
end

# live/post_live.ex
defmodule MyApp.BlogWeb.PostLive do
  use Phoenix.LiveView

  def mount(_session, socket) do
    {:ok, assign(socket, :post, %Post{})}
  end

  def render(assigns) do
    ~L"""
    <div class="post">
      <%= raw @post.content %>
    </div>
    """
  end

  def handle_event("save", %{"content" => content}, socket) do
    post = Repo.insert!(%Post{title: "New Post", content: content})
    {:noreply, assign(socket, :post, post)}
  end
end